50	fn accumulate_sum_source(params: &str) -> String {
51	    let ids: Vec<&str> = params.split(',').collect();
52	    let (p0, p1, p2) = if ids.len() >= 3 {
53	        (ids[0].trim(), ids[1].trim(), ids[2].trim())
54	    } else {
55	        ("a", "b", "sum")
56	    };
57	    format!(
58	        "pub fn accumulate_sum({p0}: i32, {p1}: i32) -> i32 {{\n    let {p2} = {p0} + {p1};\n    let extra = {p2} * 2;\n    let more = extra + {p0};\n    let result = more + {p1};\n    result\n}}\n",
59	        p0 = p0, p1 = p1, p2 = p2
60	    )
61	}
