63	// Options that take a value argument (not a path)
64	const VALUE_OPTIONS: &[&str] = &["--threshold", "--min-lines", "--min-nodes", "--format", "--lang", "--exclude"];
65	
66	fn resolve_arg_paths(args_str: &str) -> Vec<String> {
67	    let root = fixture_root();
68	    let tokens: Vec<&str> = args_str.split_whitespace().collect();
69	    let mut result = Vec::new();
70	    let mut skip_next = false;
71	    for tok in tokens.iter() {
72	        if skip_next {
73	            skip_next = false;
74	            result.push(tok.to_string());
75	            continue;
76	        }
77	        if tok.starts_with("--") || tok.starts_with('-') {
78	            if VALUE_OPTIONS.contains(tok) {
79	                skip_next = true;
80	            }
81	            result.push(tok.to_string());
82	        } else if let Some(ref r) = root {
83	            let p = Path::new(tok);
84	            if p.is_absolute() {
85	                result.push(tok.to_string());
86	            } else {
87	                result.push(Path::new(r).join(tok).to_string_lossy().to_string());
88	            }
89	        } else {
90	            result.push(tok.to_string());
91	        }
92	    }
93	    result
